ssize_t robust_read(int fd, void *buf, size_t count) {
    ssize_t bytes_read, total = 0;
    char *buffer = buf;
    while (count > 0) {
        bytes_read = read(fd, buffer, count);
        if (bytes_read < 0) {
            if (errno == EINTR)
                continue;
            return -1;
        }
        if (bytes_read == 0)
            break;
        buffer += bytes_read;
        total += bytes_read;
        count -= bytes_read;
    }
    return total;
}

ssize_t robust_write(int fd, const void *buf, size_t count) {
    ssize_t bytes_written, total = 0;
    const char *buffer = buf;
    while (count > 0) {
        bytes_written = write(fd, buffer, count);
        if (bytes_written < 0) {
            if (errno == EINTR)
                continue;
            return -1;
        }
        total += bytes_written;
        buffer += bytes_written;
        count -= bytes_written;
    }
    return total;
}

